window.bookSummaryJSON = "<p>With starred reviews from <i>School Library Journal, Booklist,</i> and <i>Kirkus Reviews</i>, this moving novel by acclaimed author Walter Dean Myers is a modern classic. In the late 1960s, Richie Perry is growing up fast on the battlefields of Vietnam. But in the war-torn jungle, every moment is a struggle to survive. All Richie wants is to make it out alive.</p>"; 
